---
layout: default
---
{%- assign locale = page.locale | default: layout.locale | default: site.locale %}

{% if page.header.overlay_color or page.header.overlay_image or page.header.image %}
  {% include page__hero.html locale=locale %}
{% endif %}

{% if page.url != "/" and site.breadcrumbs %}
  {% unless paginator %}
    {% include breadcrumbs.html locale=locale %}
  {% endunless %}
{% endif %}

<div id="main" role="main">
  {% include sidebar.html locale=locale %}

  <div class="archive">
    {% unless page.header.overlay_color or page.header.overlay_image %}
      <h1 id="page-title" class="page__title"{% if page.locale %} lang="{{ page.locale }}"{% endif %}>{{ page.title }}</h1>
    {% endunless %}

    {{ content }}

    {%- assign search_provider = site.search_provider | default: "lunr" -%}
    {%- case search_provider -%}
      {%- when "lunr" -%}
        <input type="text" id="search" class="search-input" placeholder="{{ site.data.ui-text[locale].search_placeholder_text | default: 'Enter your search term...' }}" />
        <div id="results" class="results"></div>
      {%- when "google" -%}
        <form onsubmit="return googleCustomSearchExecute();" id="cse-search-box-form-id">
        <input type="text" id="cse-search-input-box-id" class="search-input" placeholder="{{ site.data.ui-text[locale].search_placeholder_text | default: 'Enter your search term...' }}" />
        </form>
        <div id="results" class="results">
          <gcse:searchresults-only></gcse:searchresults-only>
        </div>
      {%- when "algolia" -%}
        <div class="search-searchbar"></div>
        <div class="search-hits"></div>
    {%- endcase -%}
  </div>
</div>

{% assign roles = 'User,Admin,Owner' | split: ',' %}
{% assign limit = include.limit | default: 5 %}
<div class="table-responsive">
	<table
		class="table table-vcenter{% if include.mobile %} table-mobile-md{% endif %}{% if include.card %} card-table{% endif %}{% if include.stripped %} table-striped{% endif %}{% if include.nowrap %} table-nowrap{% endif %}">
		<thead>
		<tr>
			<th>Name</th>
			<th>Title</th>

			{% unless include.avatars %}
			<th>Email</th>
			{% endunless %}

			<th>Role</th>

			{% if include.nowrap %}
			<th></th>
			{% endif %}

			<th class="w-1"></th>
		</tr>
		</thead>
		<tbody>
		{% for person in people limit: limit offset: include.offset %}
		<tr>
			{% if include.avatars %}
			<td {% if include.mobile %}data-label="Name" {% endif %}>
				<div class="d-flex py-1 align-items-center">
					{% include "ui/avatar.html" person-id=person.id class="me-2" %}
					<div class="flex-fill">
						<div class="fw-medium">{{ person.full_name }}</div>
						<div class="text-secondary"><a href="#" class="text-reset">{{ person.email }}</a></div>
					</div>
				</div>
			</td>
			{% else %}
			<td {% if include.mobile %}data-label="Name" {% endif %}>{{ person.full_name }}</td>
			{% endif %}


			{% if include.avatars %}
			<td {% if include.mobile %}data-label="Title" {% endif %}>
				<div>{{ person.job_title }}</div>
				<div class="text-secondary">{{ person.department }}</div>
			</td>
			{% else %}
			<td class="text-secondary" {% if include.mobile %}data-label="Title" {% endif %}>
				{{ person.job_title }}, {{ person.department }}
			</td>
